import psycopg2
from psycopg2 import pool

# Create a new PostgreSQL database connection pool
conn_pool = None
def create_conn_pool(minconn, maxconn, host='localhost', port=5432, dbname='hackathon_db', user='admin', password='demo123'):
    global conn_pool
    conn_pool = psycopg2.pool.SimpleConnectionPool(minconn, maxconn, host=host, port=port, dbname=dbname, user=user, password=password)

# Use the connection pool to get a new connection
def exec_query(query):
    global conn_pool
    if not conn_pool:
        raise Exception("Connection pool not created. Call create_conn_pool first.")
    
    conn = conn_pool.getconn()
    if not conn:
        raise Exception("Could not obtain database connection from pool")
    
    try:
        with conn.cursor() as cursor:
            cursor.execute(query)
            results = cursor.fetchall()
        return results
    except Exception as e:
        print(f"Error occurred while executing query: {e}")
    finally:
        # Release the connection back to the pool
        conn_pool.putconn(conn)